"""Unified signed-in home for all Balkan.works modules."""


def render_dashboard_page() -> str:
    return '''<!doctype html><html lang="sr"><head><meta charset="utf-8"><meta name="viewport" content="width=device-width,initial-scale=1"><title>Moj Balkan · Balkan.works</title><style>
:root{--ink:#092c26;--pine:#0d4036;--paper:#f7f8f4;--orange:#ff6c37;--line:#d9e3dc;--muted:#62746e;--mint:#e5f5eb}*{box-sizing:border-box}body{margin:0;background:var(--paper);font-family:Inter,system-ui,sans-serif;color:var(--ink)}.wrap{max-width:1280px;margin:auto;padding:0 25px}.nav{height:76px;display:flex;align-items:center;justify-content:space-between;border-bottom:1px solid var(--line)}.brand{font-size:24px;font-weight:900;color:var(--ink);text-decoration:none}.brand i{color:var(--orange)}.nav a:last-child{color:var(--pine);font-weight:800;text-decoration:none;font-size:14px}.hero{padding:38px 0 26px}.eyebrow{font-size:12px;letter-spacing:1.3px;text-transform:uppercase;color:var(--orange);font-weight:900}h1{font:clamp(39px,5vw,58px)/1 Georgia,serif;letter-spacing:-2px;margin:10px 0}.lead{color:var(--muted);font-size:16px}.quick{display:grid;grid-template-columns:repeat(5,1fr);gap:10px;margin:20px 0 28px}.quick a{padding:14px;background:#fff;border:1px solid var(--line);border-radius:12px;text-decoration:none;color:var(--ink);font-weight:800;font-size:14px}.quick a:hover{border-color:#8ab29f;background:var(--mint)}.metrics{display:grid;grid-template-columns:repeat(4,1fr);gap:12px;margin:20px 0}.metric,.card{background:#fff;border:1px solid var(--line);border-radius:14px}.metric{padding:17px}.metric b{display:block;font-size:28px}.metric span{font-size:12px;color:var(--muted)}.grid{display:grid;grid-template-columns:1.15fr 1fr 1fr;gap:14px;padding-bottom:45px}.card{padding:18px;min-height:215px}.card h2{font:23px Georgia,serif;margin:0 0 5px}.card p{color:var(--muted);font-size:13px;line-height:1.45}.row{border-top:1px solid var(--line);padding:11px 0;font-size:13px}.row b{display:block}.meta{color:var(--muted);font-size:12px;margin-top:3px}.empty{color:var(--muted);font-size:13px;margin-top:18px}.button{border:0;border-radius:8px;padding:9px 11px;background:var(--pine);color:#fff;font-weight:800;cursor:pointer;margin-top:8px}.warning{max-width:560px;margin:13vh auto;background:#fff;padding:30px;border:1px solid var(--line);border-radius:18px}.hidden{display:none}@media(max-width:900px){.quick{grid-template-columns:repeat(3,1fr)}.metrics{grid-template-columns:1fr 1fr}.grid{grid-template-columns:1fr 1fr}.card:first-child{grid-column:span 2}}@media(max-width:530px){.wrap{padding:0 16px}.quick{grid-template-columns:1fr 1fr}.grid{grid-template-columns:1fr}.card:first-child{grid-column:auto}.metrics{grid-template-columns:1fr 1fr}}
</style></head><body><div id="locked" class="warning"><div class="eyebrow">Balkan.works nalog</div><h1>Prvo se prijavi.</h1><p>Jedan nalog otvara tvoj profil, poruke, omiljene oglase, rezervacije i poslovne alate.</p><a href="/account">Otvori prijavu →</a></div><main id="page" class="hidden"><div class="wrap"><nav class="nav"><a class="brand" href="/">balkan<i>.</i>works</a><a href="/account">Uredi profil →</a></nav><header class="hero"><div class="eyebrow">Moj Balkan</div><h1 id="title">Dobro došao/la.</h1><p id="subtitle" class="lead">Učitavamo tvoj regionalni centar.</p></header><section class="quick"><a href="/market">⌁ Market</a><a href="/deals">◈ Deals</a><a href="/save-food">◌ Save Food</a><a href="/business">▦ Business</a><a href="/admin">⌘ Admin</a></section><section class="metrics"><div class="metric"><b id="unread">—</b><span>nepročitanih obaveštenja</span></div><div class="metric"><b id="messages">—</b><span>novih poruka</span></div><div class="metric"><b id="favorites">—</b><span>sačuvanih oglasa</span></div><div class="metric"><b id="businesses">—</b><span>poslovnih profila</span></div></section><section class="grid"><article class="card"><h2>Obaveštenja</h2><p>Važne aktivnosti svih modula, na jednom mestu.</p><button class="button" id="read-all">Označi sve kao pročitano</button><div id="notifications"></div></article><article class="card"><h2>Poruke</h2><p>Poruke sa Market oglasa i saradnji.</p><div id="inbox"></div></article><article class="card"><h2>Sačuvano</h2><p>Oglasi koje želiš da pratiš.</p><div id="saved"></div></article><article class="card"><h2>Novčanik</h2><p>Struktura za buduća plaćanja, rezervacije i pretplate.</p><div id="wallet"></div></article><article class="card"><h2>Moje firme</h2><p>Status profila, verifikacija i sadržaj firmi.</p><div id="my-businesses"></div></article><article class="card"><h2>Lokalni fokus</h2><p id="location-copy">Podesi grad u profilu kako bi prioritet dobile ponude i usluge u blizini.</p><a href="/account">Podesi lokaciju →</a></article></section></div></main><script>
const token=()=>localStorage.getItem('balkan_access_token');const auth=()=>({authorization:'Bearer '+token()});const esc=s=>String(s??'').replace(/[&<>"']/g,c=>({'&':'&amp;','<':'&lt;','>':'&gt;','"':'&quot;',"'":'&#39;'}[c]));const time=s=>s?new Date(s).toLocaleString('sr-RS'):'—';async function get(path){const r=await fetch(path,{headers:auth()});const d=await r.json().catch(()=>({}));if(!r.ok)throw new Error(d.detail||'Nije dostupno.');return d}function rows(target,items,html,empty){document.querySelector(target).innerHTML=items.length?items.slice(0,4).map(html).join(''):'<div class="empty">'+empty+'</div>'}async function load(){if(!token())return;try{const [me,notifications,inbox,favorites,wallet,businesses]=await Promise.all([get('/api/me'),get('/api/notifications'),get('/api/market/messages'),get('/api/market/favorites'),get('/api/payments/wallet'),get('/api/businesses')]);document.querySelector('#locked').classList.add('hidden');document.querySelector('#page').classList.remove('hidden');document.querySelector('#title').textContent='Zdravo, '+me.profile.display_name+'.';const place=[me.profile.city_name,me.profile.country_code].filter(Boolean).join(', ');document.querySelector('#subtitle').textContent=place?'Tvoj regionalni centar je podešen za '+place+'.':'Podesi svoju lokaciju za bolje lokalne rezultate.';document.querySelector('#location-copy').textContent=place?'Lokalne preporuke su prioritizovane za '+place+'.':'Podesi grad u profilu da aktiviraš lokalne preporuke.';document.querySelector('#unread').textContent=notifications.filter(x=>!x.is_read).length;document.querySelector('#messages').textContent=inbox.filter(x=>!x.is_read).length;document.querySelector('#favorites').textContent=favorites.length;document.querySelector('#businesses').textContent=businesses.length;rows('#notifications',notifications,x=>'<div class="row"><b>'+esc(x.title)+'</b><div>'+esc(x.body)+'</div><span class="meta">'+time(x.created_at)+(x.is_read?'':' · novo')+'</span></div>','Nema obaveštenja.');rows('#inbox',inbox,x=>'<div class="row"><b>Nova poruka</b><div>'+esc(x.body)+'</div><span class="meta">'+time(x.created_at)+'</span></div>','Nema novih poruka.');rows('#saved',favorites,x=>'<div class="row"><b>'+esc(x.title)+'</b><span class="meta">'+esc(x.city_name||x.country_code)+' · '+(x.price??'Dogovor')+' '+esc(x.currency)+'</span></div>','Još nema sačuvanih oglasa.');document.querySelector('#wallet').innerHTML='<div class="row"><b>'+Number(wallet.balance||0).toLocaleString('sr-RS',{style:'currency',currency:wallet.currency||'EUR'})+'</b><span class="meta">Trenutni balans · plaćanja nisu aktivirana</span></div>';rows('#my-businesses',businesses,x=>'<div class="row"><b>'+esc(x.name)+'</b><span class="meta">'+esc(x.city_name)+', '+esc(x.country_code)+' · '+esc(x.verification_status)+'</span></div>','Nema povezanih firmi.')}catch(error){localStorage.removeItem('balkan_access_token');document.querySelector('#locked').classList.remove('hidden');document.querySelector('#locked').innerHTML+='<p>'+esc(error.message)+'</p>'}}document.querySelector('#read-all').onclick=async()=>{try{await fetch('/api/notifications/read-all',{method:'POST',headers:auth()});load()}catch(_){}};load();
</script></body></html>'''
